<?php declare(strict_types=1);require __DIR__.'/bootstrap.php';$pageTitle='Orders';require VP3_ROOT.'/includes/account-header.php';$rows=[];if(vp3_db_available()){$stmt=vp3_db()->prepare('SELECT o.order_number,o.order_status,o.payment_status,o.total_cents,o.currency,o.created_at,GROUP_CONCAT(oi.item_name SEPARATOR ", ") items FROM orders o LEFT JOIN order_items oi ON oi.order_id=o.id WHERE o.customer_id=? GROUP BY o.id ORDER BY o.id DESC');$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();}?><h1>Orders</h1><div class="table-wrap"><table class="table"><thead><tr><th>Order</th><th>Items</th><th>Status</th><th>Payment</th><th>Total</th><th>Date</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=vp3_e($r['order_number'])?></td><td><?=vp3_e($r['items'])?></td><td><span class="badge <?=vp3_e($r['order_status'])?>"><?=vp3_e($r['order_status'])?></span></td><td><?=vp3_e($r['payment_status'])?></td><td><?=vp3_e(vp3_money((int)$r['total_cents'],$r['currency']))?></td><td><?=vp3_e($r['created_at'])?></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="6">No orders yet.</td></tr><?php endif;?></tbody></table></div><?php require VP3_ROOT.'/includes/account-footer.php';?>